const raw = query;
let scenario = 'general_engagement';
if (raw && typeof raw === 'object' && raw.scenario) {
  scenario = String(raw.scenario);
} else if (typeof raw === 'string') {
  try {
    const p = JSON.parse(raw);
    if (p && p.scenario) scenario = String(p.scenario);
  } catch (e) {}
}

const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const today = days[new Date().getDay()];

const dutyFree = [
  'Depending on the states, we would be able to work out an arrangement which we would absorb the duty and tariff for you- esentially what you see here is what you would net pay',
  'The team also shared that we can have the insured priority label ready to go for you.',
  "As a Singapore registered business, we don't have the same statutory taxes as the US. Our international clients often benefit from this when purchasing from us.",
  'Which state are you based in now?',
].join('\n');

const map = {
  offer: "I've sent your offer to the team for review and will revert",
  best_price:
    "Maybe you can send here your desired price for the piece?\nI'll forward it to the team for review and will revert",
  duty_free: dutyFree,
  shipping_delivery:
    "We ship sold watches with insured, tracked delivery. Once your order is confirmed, our team arranges dispatch and shares tracking details with you.\n\nExact carrier and delivery time depend on your destination — if you share your country or region, I can have the team confirm the options and ETA for you.",
  defer_product: "I'll check with the team and get back to you on that.",
  general_engagement:
    `Happy ${today}!\n\nHey buddy — happy to chat. Are you thinking of this piece for yourself or for someone else? If you tell me what you're looking for, I can help with next steps; anything specific about the watch I'll confirm with our team.`,
};

return map[scenario] || map.general_engagement;

const agent = $input.first().json;
const reply = String(agent.output ?? agent.text ?? '');
let replyChannel = 'chat';
try {
  const rows = $('HTTP entry').all();
  if (rows.length && rows[0].json.replyChannel === 'http') {
    replyChannel = 'http';
  }
} catch (e) {
  replyChannel = 'chat';
}
return [{ json: { reply, replyChannel } }];
